import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

class KtLintRuleEngineLoopTest {
    @Test
    fun `Given a rule A which modifies code such that it triggers a violation in rule B which runs before rule A then rerun the rules until no more violations occur`() {
        val ruleA = RuleA()
        val ruleB = RuleB()

        val code = Code.fromSnippet("val x = foo")

        val engine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { ruleB },
                RuleProvider { ruleA }
            )
        )

        val actual = engine.format(code)
        assertThat(actual).isEqualTo("val x = baz")
    }

    private class RuleA : Rule(
        ruleId = RuleId("test:rule-a"),
        about = About()
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
        ) {
            if (node is LeafElement && node.text == "foo") {
                emit(node.startOffset, "Replace foo with bar", true)
                if (autoCorrect) {
                    (node as LeafElement).replaceWithText("bar")
                }
            }
        }
    }

    private class RuleB : Rule(
        ruleId = RuleId("test:rule-b"),
        about = About()
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
        ) {
            if (node is LeafElement && node.text == "bar") {
                emit(node.startOffset, "Replace bar with baz", true)
                if (autoCorrect) {
                    (node as LeafElement).replaceWithText("baz")
                }
            }
        }
    }
}
